1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  KeyboardAvoidingView,
5	  Modal,
6	  Platform,
7	  Pressable,
8	  SafeAreaView,
9	  ScrollView,
10	  StyleSheet,
11	  Text,
12	  TextInput,
13	  type TextInputProps,
14	  View,
15	} from 'react-native';
16	import { router, useLocalSearchParams } from 'expo-router';
17	import { ChevronLeft } from 'lucide-react-native';
18	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
19	import { Chip } from '@/components/primitives/Chip';
20	import { useToast } from '@/components/primitives/Toast';
21	import { colors, radii, shadows, spacing } from '@/design/tokens';
22	import { textStyles } from '@/design/typography';
23	import { supabase } from '@/lib/supabase';
24	import type { Database } from '@/types/supabase';
25	
26	// US-055 — Edit campaign screen with cascade-cancel confirmation modal.
27	//
28	// Flow: fetch the listing (listings_owner_all RLS → owner only) → render
29	// editable fields → on Save, diff against the original. If any VERSIONED
30	// scalar field (price_cents, currency, max_submissions — per the
31	// us_010 cascade trigger at supabase/migrations/20260417150000) changed,
32	// count the listing's pending applications via PostgREST under the
33	// applications_lister_read policy, and if >0 show a confirm modal per
34	// docs/design.md §5.2 line 635 before issuing the PATCH. The DB trigger
35	// (app_private.bump_listing_version) performs the cascade + notification
36	// server-side on commit. Title/description/category edits DO NOT cascade
37	// (trigger guards on the versioned scalars only).
38	//
39	// Spec gap: pre/post conditions and sample_videos editing is deferred.
40	// Those require app_private.request_listing_version_bump to fire the cue
41	// column, and §15b threshold-refresh triggers (Codebase Pattern #52)
42	// MUST land first — both are out of scope for this story's AC which
43	// verifies the flow by editing a scalar (price).
44	
45	type Currency = 'USD' | 'EUR' | 'GBP';
46	type ListingRow = Database['public']['Tables']['listings']['Row'];
47	type ListingStatus = Database['public']['Enums']['listing_status'];
48	
49	const CURRENCIES: readonly Currency[] = ['USD', 'EUR', 'GBP'];
50	const CURRENCY_SYMBOL: Record<Currency, string> = { USD: '$', EUR: '€', GBP: '£' };
51	
52	// Price in major units with up to two decimals.
53	const PRICE_INPUT_RE = /^(\d+)?(\.\d{0,2})?$/;
54	// integer column in Postgres → cap at 2^31-1 (Codebase Pattern #131).
55	const PRICE_CENTS_MAX = 2_147_483_647;
56	const MAX_SUBMISSIONS_MAX = 99_999;
57	const MAX_SUBMISSIONS_INPUT_RE = /^\d*$/;
58	
59	function centsToDisplay(cents: number | null | undefined): string {
60	  if (cents == null) return '';
61	  if (cents % 100 === 0) return String(cents / 100);
62	  return (cents / 100).toFixed(2);
63	}
64	
65	function displayToCents(display: string): number | null {
66	  const trimmed = display.trim();
67	  if (!trimmed) return null;
68	  const n = Number.parseFloat(trimmed);
69	  if (!Number.isFinite(n) || n < 0) return null;
70	  return Math.round(n * 100);
71	}
72	
73	function isKnownCurrency(c: string): c is Currency {
74	  return (CURRENCIES as readonly string[]).includes(c);
75	}
76	
77	type LoadState =
78	  | { kind: 'loading' }
79	  | { kind: 'error'; code: 'not_found' | 'generic' }
80	  | { kind: 'loaded'; listing: ListingRow };
81	
82	export default function EditCampaignScreen() {
83	  const params = useLocalSearchParams<{ id: string }>();
84	  const listingId = typeof params.id === 'string' ? params.id : null;
85	  const toast = useToast();
86	
87	  const [state, setState] = useState<LoadState>({ kind: 'loading' });
88	
89	  // Form state. Initialized from the loaded row; "priceDisplay" is the
90	  // TextInput mirror so partial values like "12." survive keystrokes.
91	  const [title, setTitle] = useState('');
92	  const [description, setDescription] = useState('');
93	  const [priceDisplay, setPriceDisplay] = useState('');
94	  const [currency, setCurrency] = useState<Currency>('USD');
95	  const [maxSubmissionsDisplay, setMaxSubmissionsDisplay] = useState('');
96	
97	  // Modal state: null = closed, number = pending count to cascade-cancel.
98	  const [confirmCount, setConfirmCount] = useState<number | null>(null);
99	  const [saving, setSaving] = useState(false);
100	  // Synchronous lock — `saving` state updates are batched, so a fast
101	  // double-tap can enter onSave twice before the disabled prop applies
102	  // (Codebase Pattern #106).
103	  const savingRef = useRef(false);
104	
105	  useEffect(() => {
106	    if (!listingId) {
107	      setState({ kind: 'error', code: 'not_found' });
108	      return;
109	    }
110	    let cancelled = false;
111	    (async () => {
112	      const { data, error } = await supabase
113	        .from('listings')
114	        .select('*')
115	        .eq('id', listingId)
116	        .maybeSingle();
117	      if (cancelled) return;
118	      if (error) {
119	        setState({ kind: 'error', code: 'generic' });
120	        return;
121	      }
122	      if (!data) {
123	        setState({ kind: 'error', code: 'not_found' });
124	        return;
125	      }
126	      setTitle(data.title);
127	      setDescription(data.description ?? '');
128	      setPriceDisplay(centsToDisplay(data.price_cents));
129	      setCurrency(isKnownCurrency(data.currency) ? data.currency : 'USD');
130	      setMaxSubmissionsDisplay(
131	        data.max_submissions == null ? '' : String(data.max_submissions),
132	      );
133	      setState({ kind: 'loaded', listing: data });
134	    })();
135	    return () => {
136	      cancelled = true;
137	    };
138	  }, [listingId]);
139	
140	  const parsedPriceCents = useMemo(() => displayToCents(priceDisplay), [priceDisplay]);
141	  const parsedMaxSubmissions = useMemo(() => {
142	    const t = maxSubmissionsDisplay.trim();
143	    if (!t) return null;
144	    const n = Number.parseInt(t, 10);
145	    if (!Number.isFinite(n) || n <= 0) return null;
146	    return n;
147	  }, [maxSubmissionsDisplay]);
148	
149	  const original = state.kind === 'loaded' ? state.listing : null;
150	
151	  // Changed-fields diff drives both the button enable state and the
152	  // versioned-field detection. We compare raw cents/ints (not display
153	  // strings) so "12" vs "12.00" doesn't count as a change.
154	  const diff = useMemo(() => {
155	    if (!original) {
156	      return { any: false, versioned: false, changed: [] as string[] };
157	    }
158	    const changed: string[] = [];
159	    if (title.trim() !== original.title) changed.push('title');
160	    if ((description.trim() || null) !== (original.description ?? null)) {
161	      changed.push('description');
162	    }
163	    if (parsedPriceCents !== original.price_cents) changed.push('price_cents');
164	    if (currency !== original.currency) changed.push('currency');
165	    if (parsedMaxSubmissions !== original.max_submissions) changed.push('max_submissions');
166	    const versioned =
167	      changed.includes('price_cents') ||
168	      changed.includes('currency') ||
169	      changed.includes('max_submissions');
170	    return { any: changed.length > 0, versioned, changed };
171	  }, [original, title, description, parsedPriceCents, currency, parsedMaxSubmissions]);
172	
173	  const inputsValid = useMemo(() => {
174	    if (title.trim().length === 0) return false;
175	    // price_cents is NOT NULL in the schema — require a parseable value.
176	    if (parsedPriceCents === null) return false;
177	    if (parsedPriceCents > PRICE_CENTS_MAX) return false;
178	    // max_submissions is nullable — empty is valid, non-empty that fails to
179	    // parse is not.
180	    if (maxSubmissionsDisplay.trim() && parsedMaxSubmissions === null) return false;
181	    if (parsedMaxSubmissions !== null && parsedMaxSubmissions > MAX_SUBMISSIONS_MAX) {
182	      return false;
183	    }
184	    return true;
185	  }, [title, parsedPriceCents, maxSubmissionsDisplay, parsedMaxSubmissions]);
186	
187	  const canSave = state.kind === 'loaded' && diff.any && inputsValid && !saving;
188	
189	  const patchListing = useCallback(async () => {
190	    if (!listingId || !original || parsedPriceCents === null) return;
191	    savingRef.current = true;
192	    setSaving(true);
193	    const payload = {
194	      title: title.trim(),
195	      description: description.trim() || null,
196	      price_cents: parsedPriceCents,
197	      currency,
198	      max_submissions: parsedMaxSubmissions,
199	    };
200	    const { error } = await supabase.from('listings').update(payload).eq('id', listingId);
201	    savingRef.current = false;
202	    setSaving(false);
203	    if (error) {
204	      toast.show({ message: "Couldn't save changes.", variant: 'error' });
205	      return;
206	    }
207	    const msg = diff.versioned
208	      ? 'Changes saved. New version published.'
209	      : 'Changes saved.';
210	    toast.show({ message: msg, variant: 'success' });
211	    if (router.canGoBack()) router.back();
212	    else router.replace('/(lister)/campaigns');
213	  }, [
214	    listingId,
215	    original,
216	    title,
217	    description,
218	    parsedPriceCents,
219	    currency,
220	    parsedMaxSubmissions,
221	    diff.versioned,
222	    toast,
223	  ]);
224	
225	  const onSave = useCallback(async () => {
226	    if (savingRef.current) return;
227	    if (!canSave || !listingId) return;
228	    // Non-versioned edits skip the cascade modal — no cascade server-side,
229	    // no creators to warn about.
230	    if (!diff.versioned) {
231	      void patchListing();
232	      return;
233	    }
234	    // Versioned edit → count pending applications BEFORE writing, so we
235	    // can show the exact cascade impact to the lister. If listing isn't
236	    // 'active' the trigger wouldn't cascade anyway, but we still query
237	    // under the same RLS policy — a non-active listing simply can't have
238	    // pending applications in this project (public_read gates on active).
239	    savingRef.current = true;
240	    setSaving(true);
241	    const { count, error } = await supabase
242	      .from('applications')
243	      .select('id', { count: 'exact', head: true })
244	      .eq('listing_id', listingId)
245	      .eq('status', 'pending');
246	    savingRef.current = false;
247	    setSaving(false);
248	    if (error) {
249	      toast.show({ message: "Couldn't check pending applications.", variant: 'error' });
250	      return;
251	    }
252	    const n = count ?? 0;
253	    if (n === 0) {
254	      // Nothing to cascade — commit directly with no interstitial.
255	      void patchListing();
256	      return;
257	    }
258	    setConfirmCount(n);
259	  }, [canSave, listingId, diff.versioned, patchListing, toast]);
260	
261	  const onConfirmCascade = useCallback(() => {
262	    setConfirmCount(null);
263	    void patchListing();
264	  }, [patchListing]);
265	
266	  const onDismissConfirm = useCallback(() => setConfirmCount(null), []);
267	
268	  const onBack = useCallback(() => {
269	    if (router.canGoBack()) router.back();
270	    else router.replace('/(lister)/campaigns');
271	  }, []);
272	
273	  if (state.kind === 'loading') {
274	    return (
275	      <SafeAreaView style={[styles.root, styles.center]}>
276	        <ActivityIndicator color={colors.ink} />
277	      </SafeAreaView>
278	    );
279	  }
280	
281	  if (state.kind === 'error') {
282	    return (
283	      <SafeAreaView style={[styles.root, styles.center]}>
284	        <Text style={[textStyles.body, { color: colors.danger, textAlign: 'center' }]}>
285	          {state.code === 'not_found' ? "Campaign not found." : "Couldn't load campaign."}
286	        </Text>
287	        <View style={{ height: spacing.lg }} />
288	        <ButtonSecondary label="Back" onPress={onBack} testID="edit-error-back" />
289	      </SafeAreaView>
290	    );
291	  }
292	
293	  return (
294	    <SafeAreaView style={styles.root}>
295	      <KeyboardAvoidingView
296	        style={styles.flex}
297	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
298	      >
299	        <ScrollView
300	          contentContainerStyle={styles.scroll}
301	          keyboardShouldPersistTaps="handled"
302	        >
303	          <View style={styles.header}>
304	            <Pressable
305	              onPress={onBack}
306	              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
307	              accessibilityRole="button"
308	              accessibilityLabel="Back"
309	              testID="edit-back"
310	              style={styles.backBtn}
311	            >
312	              <ChevronLeft size={24} color={colors.ink} />
313	            </Pressable>
314	            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
315	              {statusLabel(state.listing.status)}
316	            </Text>
317	            <Text style={[textStyles.display, styles.title]}>Edit campaign</Text>
318	            <Text
319	              style={[textStyles.body, styles.subtitle]}
320	              maxFontSizeMultiplier={1.3}
321	            >
322	              Changes to price, currency, or max submissions cancel pending applications.
323	            </Text>
324	          </View>
325	
326	          <View style={styles.fields}>
327	            <Field
328	              label="Title"
329	              value={title}
330	              onChange={setTitle}
331	              autoCapitalize="sentences"
332	              testID="edit-title"
333	            />
334	            <Field
335	              label="Description"
336	              value={description}
337	              onChange={setDescription}
338	              autoCapitalize="sentences"
339	              multiline
340	              testID="edit-description"
341	            />
342	            <Field
343	              label="Price"
344	              value={priceDisplay}
345	              onChange={(next) => {
346	                if (next !== '' && !PRICE_INPUT_RE.test(next)) return;
347	                setPriceDisplay(next);
348	              }}
349	              placeholder="0.00"
350	              keyboardType="decimal-pad"
351	              prefix={CURRENCY_SYMBOL[currency]}
352	              testID="edit-price"
353	            />
354	
355	            <View style={styles.field}>
356	              <Text style={[textStyles.caption, styles.label]}>Currency</Text>
357	              <View style={styles.chipRow}>
358	                {CURRENCIES.map((c) => (
359	                  <Chip
360	                    key={c}
361	                    label={c}
362	                    active={currency === c}
363	                    onPress={() => setCurrency(c)}
364	                    accessibilityLabel={`Currency ${c}`}
365	                    testID={`edit-currency-${c}`}
366	                  />
367	                ))}
368	              </View>
369	            </View>
370	
371	            <Field
372	              label="Max submissions (optional)"
373	              value={maxSubmissionsDisplay}
374	              onChange={(next) => {
375	                if (next !== '' && !MAX_SUBMISSIONS_INPUT_RE.test(next)) return;
376	                if (next.length > 5) return;
377	                setMaxSubmissionsDisplay(next);
378	              }}
379	              placeholder="Leave blank for unlimited"
380	              keyboardType="number-pad"
381	              testID="edit-max-submissions"
382	            />
383	          </View>
384	
385	          <ButtonPrimary
386	            label="Save changes"
387	            onPress={onSave}
388	            disabled={!canSave}
389	            loading={saving && confirmCount === null}
390	            accessibilityLabel="Save campaign changes"
391	            testID="edit-save"
392	          />
393	        </ScrollView>
394	      </KeyboardAvoidingView>
395	
396	      <CascadeConfirmModal
397	        count={confirmCount}
398	        saving={saving}
399	        onConfirm={onConfirmCascade}
400	        onDismiss={onDismissConfirm}
401	      />
402	    </SafeAreaView>
403	  );
404	}
405	
406	function statusLabel(s: ListingStatus): string {
407	  switch (s) {
408	    case 'active':
409	      return 'ACTIVE';
410	    case 'draft':
411	      return 'DRAFT';
412	    case 'paused':
413	      return 'PAUSED';
414	    case 'closed':
415	      return 'CLOSED';
416	    case 'archived':
417	      return 'ARCHIVED';
418	  }
419	}
420	
421	type CascadeConfirmModalProps = {
422	  count: number | null;
423	  saving: boolean;
424	  onConfirm: () => void;
425	  onDismiss: () => void;
426	};
427	
428	// Centered alert-style confirm. Design.md §3.3 carves out "modals (except
429	// confirmations) are bottom sheets" — confirmations are a centered card
430	// per §5.2 line 635. Keeps the same neubrutalist language (hard shadow,
431	// 2px ink border) as every other surface.
432	function CascadeConfirmModal({
433	  count,
434	  saving,
435	  onConfirm,
436	  onDismiss,
437	}: CascadeConfirmModalProps) {
438	  const visible = count !== null;
439	  return (
440	    <Modal
441	      visible={visible}
442	      transparent
443	      animationType="fade"
444	      statusBarTranslucent
445	      onRequestClose={onDismiss}
446	      testID="edit-cascade-modal"
447	    >
448	      <View style={styles.modalRoot}>
449	        <Pressable
450	          style={StyleSheet.absoluteFill}
451	          onPress={saving ? undefined : onDismiss}
452	          accessible={false}
453	          importantForAccessibility="no"
454	        />
455	        <View
456	          style={[styles.modalCard, shadows.hard]}
457	          accessibilityViewIsModal
458	          accessibilityLabel="Confirm cascade"
459	        >
460	          <Text style={[textStyles.h2, styles.modalTitle]} maxFontSizeMultiplier={1.3}>
461	            Cancel pending applications?
462	          </Text>
463	          <Text style={[textStyles.body, styles.modalBody]} maxFontSizeMultiplier={1.3}>
464	            {cascadeMessage(count)}
465	          </Text>
466	          <View style={styles.modalActions}>
467	            <View style={styles.modalActionItem}>
468	              <ButtonSecondary
469	                label="Cancel"
470	                onPress={onDismiss}
471	                disabled={saving}
472	                testID="edit-cascade-cancel"
473	              />
474	            </View>
475	            <View style={styles.modalActionItem}>
476	              <ButtonPrimary
477	                label="Continue"
478	                onPress={onConfirm}
479	                loading={saving}
480	                testID="edit-cascade-confirm"
481	              />
482	            </View>
483	          </View>
484	        </View>
485	      </View>
486	    </Modal>
487	  );
488	}
489	
490	function cascadeMessage(count: number | null): string {
491	  const n = count ?? 0;
492	  const noun = n === 1 ? 'pending application' : 'pending applications';
493	  return `This will cancel ${n} ${noun}. They'll be notified.`;
494	}
495	
496	type FieldProps = {
497	  label: string;
498	  value: string;
499	  onChange: (next: string) => void;
500	  placeholder?: string;
501	  autoCapitalize?: TextInputProps['autoCapitalize'];
502	  keyboardType?: TextInputProps['keyboardType'];
503	  multiline?: boolean;
504	  prefix?: string;
505	  testID?: string;
506	};
507	
508	function Field({
509	  label,
510	  value,
511	  onChange,
512	  placeholder,
513	  autoCapitalize,
514	  keyboardType,
515	  multiline,
516	  prefix,
517	  testID,
518	}: FieldProps) {
519	  return (
520	    <View style={styles.field}>
521	      <Text style={[textStyles.caption, styles.label]}>{label}</Text>
522	      <View style={[styles.inputWrap, shadows.hard, multiline && styles.inputWrapMultiline]}>
523	        {prefix ? <Text style={[textStyles.body, styles.prefix]}>{prefix}</Text> : null}
524	        <TextInput
525	          value={value}
526	          onChangeText={onChange}
527	          placeholder={placeholder}
528	          placeholderTextColor={colors.ink40}
529	          autoCapitalize={autoCapitalize}
530	          keyboardType={keyboardType}
531	          multiline={multiline}
532	          maxFontSizeMultiplier={1.3}
533	          style={[textStyles.body, styles.input, multiline && styles.inputMultiline]}
534	          accessibilityLabel={label}
535	          testID={testID}
536	        />
537	      </View>
538	    </View>
539	  );
540	}
