542	const styles = StyleSheet.create({
543	  root: { flex: 1, backgroundColor: colors.canvas },
544	  flex: { flex: 1 },
545	  center: { alignItems: 'center', justifyContent: 'center', padding: spacing.xl },
546	  scroll: {
547	    padding: spacing.base,
548	    gap: spacing.xl,
549	    paddingBottom: spacing.xxxl,
550	  },
551	  header: {
552	    gap: spacing.xs,
