562	  title: { color: colors.ink },
563	  subtitle: { color: colors.ink70 },
564	  fields: { gap: spacing.base },
565	  field: { gap: spacing.xs },
566	  label: { color: colors.ink70 },
567	  inputWrap: {
568	    backgroundColor: colors.surface,
569	    borderRadius: radii.input,
570	    borderWidth: 2,
571	    borderColor: colors.ink,
572	    flexDirection: 'row',
573	    alignItems: 'center',
574	  },
575	  inputWrapMultiline: { alignItems: 'flex-start' },
576	  prefix: {
577	    paddingLeft: spacing.base,
578	    color: colors.ink70,
579	  },
580	  input: {
581	    flex: 1,
582	    paddingHorizontal: spacing.base,
583	    paddingVertical: spacing.md,
584	    color: colors.ink,
585	    minHeight: 48,
586	  },
587	  inputMultiline: {
588	    minHeight: 120,
589	    textAlignVertical: 'top',
590	  },
591	  chipRow: {
592	    flexDirection: 'row',
593	    gap: spacing.sm,
594	  },
