1	import { useCallback } from 'react';
2	import {
3	  KeyboardAvoidingView,
4	  Platform,
5	  Pressable,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  TextInput,
11	  View,
12	} from 'react-native';
13	import { router } from 'expo-router';
14	import { ChevronLeft, Trash2 } from 'lucide-react-native';
15	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
16	import { colors, radii, shadows, spacing } from '@/design/tokens';
17	import { textStyles } from '@/design/typography';
18	import { classifyVideoUrl } from '@/lib/oembed';
19	import { useWizard } from '@/screens/campaign-wizard/WizardStore';
20	
21	// US-052 — Create-campaign wizard step 4 (sample videos + max submissions).
22	// Per-row URL validation reuses `classifyVideoUrl` from `src/lib/oembed.ts`
23	// so the wizard preview and the server-side submit path (US-046 / the
24	// submit-video edge function) agree on what counts as a TikTok or Instagram
25	// URL. Empty rows are allowed and will be filtered at publish (step-5) —
