1	// Edge function: create-listing (US-053)
2	//
3	// Contract:
4	//   POST {
5	//     title:           string (1..200 after trim),
6	//     description:     string (1..5000 after trim),
7	//     price_cents:     number (integer, >= 0, <= 1e9),
8	//     currency:        'USD' | 'EUR' | 'GBP',
9	//     max_submissions: number | null (integer, 1..99999),
10	//     pre_conditions: Array<{
11	//       platform: 'tiktok' | 'instagram',
12	//       metric:   'followers' | 'avg_views',
13	//       threshold: number (integer, >= 0),
14	//     }>,
15	//     post_conditions: Array<{ id: string (uuid), text: string (1..500 trim) }>,
16	//     sample_urls:     Array<string>  // each must classify as tiktok|instagram
17	//   }
18	//     → 201 { listing_id: string, version_id: string }
19	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST', field?: string }
20	//     → 401 { error: 'UNAUTHORIZED' }
21	//     → 403 { error: 'FORBIDDEN' }                 // non-lister role
22	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
23	//
24	// Auth: Marketify HS256 JWT (MARKETIFY_JWT_SECRET), app_role must be 'lister'.
25	//       Gateway `verify_jwt` is disabled because Supabase-issued JWTs aren't
26	//       the same namespace — the handler enforces auth via _shared/jwt.ts.
27	//
28	// The handler is the validation boundary: the RPC assumes caller has already
29	// normalized shape. We classify sample URLs here (via _shared/oembed.ts) so
30	// the DB sees the same platform label the wizard preview showed the user.
31	// Empty / whitespace-only URL rows are dropped silently (the wizard allows
32	// blank rows as drafting state per US-052).
33	
34	import { createClient } from "npm:@supabase/supabase-js@2";
35	import { verifyJwt } from "../_shared/jwt.ts";
36	import { corsHeaders } from "../_shared/cors.ts";
37	import { classifyVideoUrl } from "../_shared/oembed.ts";
38	
39	const UUID_RE =
40	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
41	
42	const TITLE_MIN = 1;
43	const TITLE_MAX = 200;
44	const DESCRIPTION_MIN = 1;
45	const DESCRIPTION_MAX = 5000;
46	const PRICE_CENTS_MAX = 1_000_000_000;
47	const MAX_SUBMISSIONS_MAX = 99_999;
48	const POST_TEXT_MAX = 500;
49	const PRE_CONDITIONS_MAX = 10;
50	const POST_CONDITIONS_MAX = 20;
51	const SAMPLE_URLS_MAX = 10;
52	// Cap pre-condition thresholds at PG int32 max — the RPC casts threshold to
53	// `::integer` when populating the min_followers_* cache columns, so a value
54	// above 2,147,483,647 would blow up inside the transaction as a DB_ERROR
55	// instead of the 400 INVALID_REQUEST the caller actually deserves.
56	const PRE_THRESHOLD_MAX = 2_147_483_647;
57	const ALLOWED_CURRENCIES = new Set(["USD", "EUR", "GBP"]);
58	const ALLOWED_PRE_PLATFORMS = new Set(["tiktok", "instagram"]);
59	const ALLOWED_PRE_METRICS = new Set(["followers", "avg_views"]);
60	
61	interface RawRequest {
62	  title?: unknown;
63	  description?: unknown;
64	  price_cents?: unknown;
65	  currency?: unknown;
66	  max_submissions?: unknown;
67	  pre_conditions?: unknown;
68	  post_conditions?: unknown;
69	  sample_urls?: unknown;
70	}
71	
72	interface RawPreCondition {
73	  platform?: unknown;
74	  metric?: unknown;
75	  threshold?: unknown;
76	}
77	
78	interface RawPostCondition {
79	  id?: unknown;
80	  text?: unknown;
81	}
82	
83	interface NormalizedPayload {
84	  title: string;
85	  description: string;
86	  price_cents: number;
87	  currency: string;
88	  max_submissions: number | null;
89	  pre_conditions: Array<{
90	    platform: "tiktok" | "instagram";
91	    metric: "followers" | "avg_views";
92	    threshold: number;
93	  }>;
94	  post_conditions: Array<{ id: string; text: string }>;
95	  sample_videos: Array<{ platform: "tiktok" | "instagram"; url: string }>;
96	}
97	
98	function jsonResponse(status: number, body: unknown): Response {
99	  return new Response(JSON.stringify(body), {
100	    status,
101	    headers: { ...corsHeaders, "Content-Type": "application/json" },
102	  });
103	}
104	
105	function bearerToken(req: Request): string | null {
106	  const raw = req.headers.get("Authorization") ??
107	    req.headers.get("authorization");
108	  if (!raw) return null;
109	  const m = raw.match(/^Bearer\s+(.+)$/i);
110	  return m ? m[1].trim() : null;
111	}
112	
113	function isNonNegativeSafeInt(n: unknown, max: number): n is number {
114	  return typeof n === "number" && Number.isFinite(n) && Number.isInteger(n) &&
115	    n >= 0 && n <= max;
116	}
117	
118	function validate(body: RawRequest):
119	  | { ok: true; payload: NormalizedPayload }
120	  | { ok: false; field: string } {
121	  if (typeof body.title !== "string") return { ok: false, field: "title" };
122	  const title = body.title.trim();
123	  if (title.length < TITLE_MIN || title.length > TITLE_MAX) {
124	    return { ok: false, field: "title" };
125	  }
126	
127	  if (typeof body.description !== "string") {
128	    return { ok: false, field: "description" };
129	  }
130	  const description = body.description.trim();
131	  if (
132	    description.length < DESCRIPTION_MIN ||
133	    description.length > DESCRIPTION_MAX
134	  ) {
135	    return { ok: false, field: "description" };
136	  }
137	
138	  if (!isNonNegativeSafeInt(body.price_cents, PRICE_CENTS_MAX)) {
139	    return { ok: false, field: "price_cents" };
140	  }
141	  const priceCents = body.price_cents;
142	
143	  if (typeof body.currency !== "string" || !ALLOWED_CURRENCIES.has(body.currency)) {
144	    return { ok: false, field: "currency" };
145	  }
146	  const currency = body.currency;
147	
148	  let maxSubmissions: number | null = null;
149	  if (body.max_submissions !== null && body.max_submissions !== undefined) {
150	    if (
151	      typeof body.max_submissions !== "number" ||
152	      !Number.isInteger(body.max_submissions) ||
153	      body.max_submissions < 1 ||
154	      body.max_submissions > MAX_SUBMISSIONS_MAX
155	    ) {
156	      return { ok: false, field: "max_submissions" };
157	    }
158	    maxSubmissions = body.max_submissions;
159	  }
160	
161	  if (!Array.isArray(body.pre_conditions)) {
162	    return { ok: false, field: "pre_conditions" };
163	  }
164	  if (body.pre_conditions.length > PRE_CONDITIONS_MAX) {
165	    return { ok: false, field: "pre_conditions" };
166	  }
167	  const preConditions: NormalizedPayload["pre_conditions"] = [];
168	  for (const rawRow of body.pre_conditions) {
169	    const row = rawRow as RawPreCondition;
170	    if (typeof row !== "object" || row === null) {
171	      return { ok: false, field: "pre_conditions" };
172	    }
173	    if (typeof row.platform !== "string" || !ALLOWED_PRE_PLATFORMS.has(row.platform)) {
174	      return { ok: false, field: "pre_conditions.platform" };
175	    }
176	    if (typeof row.metric !== "string" || !ALLOWED_PRE_METRICS.has(row.metric)) {
177	      return { ok: false, field: "pre_conditions.metric" };
178	    }
179	    if (!isNonNegativeSafeInt(row.threshold, PRE_THRESHOLD_MAX)) {
180	      return { ok: false, field: "pre_conditions.threshold" };
181	    }
182	    preConditions.push({
183	      platform: row.platform as "tiktok" | "instagram",
184	      metric: row.metric as "followers" | "avg_views",
185	      threshold: row.threshold,
186	    });
187	  }
188	
189	  if (!Array.isArray(body.post_conditions)) {
190	    return { ok: false, field: "post_conditions" };
191	  }
192	  if (body.post_conditions.length > POST_CONDITIONS_MAX) {
193	    return { ok: false, field: "post_conditions" };
194	  }
195	  const postConditions: NormalizedPayload["post_conditions"] = [];
196	  const seenPostIds = new Set<string>();
