1	// Client-side URL classifier + TikTok oEmbed fetch, used by the
2	// submission composer (US-046) to render a live preview card before
3	// the creator taps Submit.
4	//
5	// Mirrors the server-side helper at `supabase/functions/_shared/oembed.ts`
6	// so client validation gives the same platform/external_id answer the
7	// submit-video edge function will reach. The server remains the source
8	// of truth — a green client-side preview is NOT a submission guarantee;
9	// the edge function re-classifies + re-fetches before persisting.
10	//
11	// Instagram: classification-only. The Meta Graph instagram_oembed
12	// endpoint requires an app-level token we don't provision in the
13	// client (and don't want to — it'd ship with the JS bundle). IG URLs
14	// render a platform-label preview card; server-side submission is
15	// still regex-shape only per docs/tech-architecture.md §3h.
16	
17	export type OembedPlatform = 'tiktok' | 'instagram';
18	
19	export interface UrlClassification {
20	  platform: OembedPlatform;
21	  externalId: string | null;
22	}
23	
24	export interface TikTokOembedPreview {
25	  thumbnailUrl: string | null;
26	  authorHandle: string | null;
27	  title: string | null;
28	  raw: Record<string, unknown>;
29	}
30	
31	const TIKTOK_CANONICAL_RE =
32	  /^https:\/\/(?:www\.)?tiktok\.com\/@[A-Za-z0-9._-]+\/video\/(\d+)/i;
33	const TIKTOK_SHORTLINK_RE =
34	  /^https:\/\/(?:vm|vt)\.tiktok\.com\/[A-Za-z0-9]+\/?/i;
35	const TIKTOK_TLINK_RE =
36	  /^https:\/\/(?:www\.)?tiktok\.com\/t\/[A-Za-z0-9]+\/?/i;
37	
38	const INSTAGRAM_RE =
39	  /^https:\/\/(?:www\.)?instagram\.com\/(?:p|reel|tv)\/([A-Za-z0-9_-]+)\/?/i;
40	
41	export function classifyVideoUrl(url: string): UrlClassification | null {
42	  if (typeof url !== 'string') return null;
43	  const trimmed = url.trim();
44	  if (trimmed.length === 0) return null;
45	
46	  const canon = trimmed.match(TIKTOK_CANONICAL_RE);
47	  if (canon) {
48	    return { platform: 'tiktok', externalId: canon[1] };
49	  }
50	  if (TIKTOK_SHORTLINK_RE.test(trimmed) || TIKTOK_TLINK_RE.test(trimmed)) {
51	    return { platform: 'tiktok', externalId: null };
52	  }
53	  const ig = trimmed.match(INSTAGRAM_RE);
54	  if (ig) {
55	    return { platform: 'instagram', externalId: ig[1] };
56	  }
57	  return null;
58	}
59	
60	export async function fetchTikTokOembed(
61	  url: string,
62	  signal?: AbortSignal,
63	): Promise<TikTokOembedPreview | null> {
64	  const endpoint = `https://www.tiktok.com/oembed?url=${encodeURIComponent(url)}`;
65	  const response = await fetch(endpoint, { signal });
66	  if (response.status === 404 || response.status === 400) {
67	    return null;
68	  }
69	  if (!response.ok) {
70	    throw new Error(`TikTok oEmbed HTTP ${response.status}`);
71	  }
72	  const data = (await response.json()) as Record<string, unknown>;
73	  const thumbnailUrl = typeof data.thumbnail_url === 'string'
74	    ? data.thumbnail_url
75	    : null;
76	  const authorHandle = extractTikTokAuthorHandle(data);
77	  const title = typeof data.title === 'string' && data.title.trim().length > 0
78	    ? data.title.trim()
79	    : null;
80	  return { thumbnailUrl, authorHandle, title, raw: data };
81	}
82	
83	function extractTikTokAuthorHandle(
84	  data: Record<string, unknown>,
85	): string | null {
86	  const candidates = [data.author_unique_id, data.author_name];
87	  for (const raw of candidates) {
88	    if (typeof raw === 'string') {
89	      const h = raw.trim().replace(/^@+/, '');
90	      if (h.length > 0) return h;
91	    }
92	  }
93	  return null;
94	}
