      savingRef.current = false;
      setSaving(false);
      if (error) {
        toast.show({ message: "Couldn't check pending applications.", variant: 'error' });
        return;
      }
      const n = count ?? 0;
      if (n === 0) {
        // No cascade impact — chain through directly.
        await runScalarThenSamples(scalarsAlsoChanged);
        return;
      }
      // Open modal as 'samples' kind because the server-side confirm is
      // the actual gate; the modal's Continue handler chains both writes.
      setCascadeTrigger({ kind: 'samples', count: n });
      return;
    }

    // Non-versioned scalars also changed (e.g. title) — PATCH them first
    // (no cascade), then route samples through the edge function, which
    // gates its own cascade.
    if (scalarsAlsoChanged) {
      await patchScalarsThenInvoke(false);
      return;
    }

    // Only samples changed — single edge-function call. The server gates
    // the cascade and may return needs_confirmation, which opens the modal.
    void invokeUpdateSamples(false);
    return;
  }

  // Branch B: scalars only.
  // Non-versioned scalar edits skip the cascade modal — no cascade
  // server-side, no creators to warn about.
  if (!diff.scalarVersioned) {
    void patchScalars();
    return;
  }
  // Versioned scalar edit → count pending applications BEFORE writing,
  // so we can show the exact cascade impact to the lister. If listing
  // isn't 'active' the trigger wouldn't cascade anyway, but we still
  // query under the same RLS policy — a non-active listing simply can't
  // have pending applications in this project (public_read gates on
  // active).
  savingRef.current = true;
  setSaving(true);
  const { count, error } = await supabase
    .from('applications')
    .select('id', { count: 'exact', head: true })
    .eq('listing_id', listingId)
    .eq('status', 'pending');
  savingRef.current = false;
  setSaving(false);
  if (error) {
    toast.show({ message: "Couldn't check pending applications.", variant: 'error' });
    return;
  }
  const n = count ?? 0;
  if (n === 0) {
    // Nothing to cascade — commit directly with no interstitial.
    void patchScalars();
    return;
  }
  setCascadeTrigger({ kind: 'scalar', count: n });
  // Helper closures defined below.
  async function patchScalarsThenInvoke(confirmCascade: boolean) {
    if (!listingId || !original || parsedPriceCents === null) return;
    savingRef.current = true;
    setSaving(true);
    const payload = {
      title: title.trim(),
      description: description.trim() || null,
      price_cents: parsedPriceCents,
      currency,
      max_submissions: parsedMaxSubmissions,
    };
    const { error: patchErr } = await supabase
      .from('listings')
      .update(payload)
      .eq('id', listingId);
    if (patchErr) {
      savingRef.current = false;
      setSaving(false);
      toast.show({ message: "Couldn't save changes.", variant: 'error' });
      return;
    }
    // Release the local lock; invokeUpdateSamples re-takes it.
    savingRef.current = false;
    setSaving(false);
    await invokeUpdateSamples(confirmCascade);
  }
  async function runScalarThenSamples(_scalarsAlsoChanged: boolean) {
    void _scalarsAlsoChanged;
    await patchScalarsThenInvoke(true);
  }
}, [
  canSave,
  listingId,
  diff.samplesChanged,
  diff.scalarVersioned,
  diff.changed,
  patchScalars,
  invokeUpdateSamples,
  toast,
  original,
  parsedPriceCents,
  title,
  description,
  currency,
  parsedMaxSubmissions,
]);

const onConfirmCascade = useCallback(async () => {
  const trigger = cascadeTrigger;
  if (!trigger) return;
